import { useMemo, useState, type FormEvent, type ReactNode } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Link, useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { toast } from 'sonner';
import { Calculator, CheckCircle2, ChevronLeft, ChevronRight, CircleDollarSign, FilePlus2, GitBranch, KeyRound, Plus, ShieldCheck } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { ConfirmDialog } from '@/components/ui/Dialog';
import { EmptyState } from '@/components/ui/EmptyState';
import { Input } from '@/components/ui/Input';
import { Label } from '@/components/ui/Label';
import { Textarea } from '@/components/ui/Textarea';
import { multiCompanyService, type GovernedPage } from '../services/multi-company-service';
import type {
  Company, CompanyCreateRequest, CompanyHierarchyNode, CompanyRole, ConfigurationVersion, ConsolidationRun,
  EliminationEntry, IntercompanyTransaction, MultiCompanySettings, PricingMethod,
  ReconciliationRow, RuntimeEnvironment, TransactionType, TransferPricingRule,
  TranslationMethod, UUID,
} from '../contracts';
import { BackButton, GovernedError, InlineWarning, LoadingPage, PageScaffold, StatusPill } from '../components/PageScaffold';
import { useUnsavedChanges } from '../hooks/useUnsavedChanges';

const PATHS = { companies: '/multi-company/companies', transactions: '/multi-company/transactions', consolidations: '/multi-company/consolidations', pricing: '/multi-company/transfer-pricing', settings: '/multi-company/settings' } as const;
const newKey = (): string => crypto.randomUUID();

interface Column<T> { label: string; render: (item: T) => ReactNode }
function ResourceList<T extends { id?: string; transaction_id?: string }>({ title, description, queryKey, load, columns, createPath, createLabel, emptyTitle, emptyDescription }: { title: string; description: string; queryKey: string; load: (filters: { page: number; page_size: number; search?: string; ordering?: string }) => Promise<GovernedPage<T>>; columns: readonly Column<T>[]; createPath?: string; createLabel?: string; emptyTitle: string; emptyDescription: string }) {
  const [searchParams, setSearchParams] = useSearchParams();
  const page = Math.max(1, Number(searchParams.get('page') ?? 1) || 1);
  const search = searchParams.get('search') ?? '';
  const ordering = searchParams.get('ordering') ?? '';
  const [draftSearch, setDraftSearch] = useState(search);
  const query = useQuery({ queryKey: [queryKey, page, search, ordering], queryFn: () => load({ page, page_size: 25, search: search || undefined, ordering: ordering || undefined }) });
  const updateParams = (changes: Readonly<Record<string, string | null>>) => { const next = new URLSearchParams(searchParams); Object.entries(changes).forEach(([key, value]) => value ? next.set(key, value) : next.delete(key)); setSearchParams(next); };
  if (query.isLoading) return <LoadingPage title={`Loading ${title}`} />;
  if (query.error) return <PageScaffold title={title} description={description}><GovernedError error={query.error} onRetry={() => void query.refetch()} /></PageScaffold>;
  const result = query.data;
  return <PageScaffold title={title} description={description} actions={createPath && <Button onClick={() => location.assign(createPath)}><Plus className="mr-2 h-4 w-4" />{createLabel ?? 'Create'}</Button>}>
    <Card><CardContent className="p-4"><form className="flex flex-col gap-3 sm:flex-row" onSubmit={(event) => { event.preventDefault(); updateParams({ search: draftSearch.trim() || null, page: null }); }}><Label className="sr-only" htmlFor={`${queryKey}-search`}>Search</Label><Input id={`${queryKey}-search`} value={draftSearch} onChange={(event) => setDraftSearch(event.target.value)} placeholder="Search records…" className="sm:max-w-md" /><Button type="submit" variant="secondary">Search</Button>{search && <Button type="button" variant="ghost" onClick={() => { setDraftSearch(''); updateParams({ search: null, page: null }); }}>Clear</Button>}</form></CardContent></Card>
    {!result?.data.length ? <EmptyState icon={FilePlus2} title={emptyTitle} description={emptyDescription} action={createPath ? { label: createLabel ?? 'Create', onClick: () => location.assign(createPath) } : undefined} /> : <Card className="overflow-hidden"><div className="overflow-x-auto"><table className="w-full min-w-[720px] text-sm"><thead className="border-b border-border bg-muted/60"><tr>{columns.map((column) => <th key={column.label} scope="col" className="px-4 py-3 text-left font-medium text-muted-foreground">{column.label}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.data.map((item) => <tr key={item.id ?? item.transaction_id} className="transition-colors hover:bg-muted/40">{columns.map((column) => <td key={column.label} className="px-4 py-4 align-top">{column.render(item)}</td>)}</tr>)}</tbody></table></div><div className="flex items-center justify-between border-t border-border p-4"><span className="text-sm text-muted-foreground">Page {result.pagination.page} of {Math.max(1, result.pagination.total_pages)} · {result.pagination.count} records</span><div className="flex gap-2"><Button size="sm" variant="outline" disabled={!result.pagination.has_previous} onClick={() => updateParams({ page: String(page - 1) })}><ChevronLeft className="h-4 w-4" /><span className="sr-only">Previous page</span></Button><Button size="sm" variant="outline" disabled={!result.pagination.has_next} onClick={() => updateParams({ page: String(page + 1) })}><ChevronRight className="h-4 w-4" /><span className="sr-only">Next page</span></Button></div></div></Card>}
  </PageScaffold>;
}

function DetailGrid({ entries }: { entries: readonly [string, ReactNode][] }) { return <dl className="grid gap-5 sm:grid-cols-2 xl:grid-cols-3">{entries.map(([label, value]) => <div key={label}><dt className="text-xs font-medium uppercase tracking-wide text-muted-foreground">{label}</dt><dd className="mt-1 break-words text-sm text-foreground">{value ?? '—'}</dd></div>)}</dl>; }
function MissingId(): ReactNode { return <PageScaffold title="Invalid route" description="This page needs a valid record identifier."><InlineWarning>Return to the list and select a record.</InlineWarning></PageScaffold>; }

export function CompanyListPage() {
  return <ResourceList<Company> title="Companies" description="Manage legal entities, hierarchy, fiscal context, and lifecycle without losing historical evidence." queryKey="multi-company-companies" load={(filters) => multiCompanyService.listCompanies(filters)} createPath={`${PATHS.companies}/new`} createLabel="Create company" emptyTitle="Build your company structure" emptyDescription="Create the first legal entity, then connect subsidiaries and intercompany workflows." columns={[
    { label: 'Company', render: (company) => <Link className="font-medium text-primary hover:underline" to={`${PATHS.companies}/${company.id}`}>{company.company_code} · {company.company_name}</Link> },
    { label: 'Currency', render: (company) => company.currency }, { label: 'Group', render: (company) => company.consolidation_group || 'Ungrouped' },
    { label: 'Parent', render: (company) => company.parent_company_name ?? 'Top level' }, { label: 'Status', render: (company) => <StatusPill value={company.is_active ? 'active' : 'inactive'} /> },
  ]} />;
}

// Orchestrates permission-aware commands and every governed record state on one surface.
// eslint-disable-next-line complexity
export function CompanyDetailPage() {
  const { id } = useParams(); const navigate = useNavigate(); const client = useQueryClient(); const [confirm, setConfirm] = useState<'deactivate' | 'delete' | null>(null);
  const query = useQuery({ queryKey: ['multi-company-company', id], queryFn: () => multiCompanyService.getCompany(id!), enabled: Boolean(id) });
  const command = useMutation({ mutationFn: async (kind: 'deactivate' | 'delete') => { const company = query.data?.data; if (!company || !id) throw new Error('Company is unavailable'); if (kind === 'delete') return multiCompanyService.deleteCompany(id, company.version); return multiCompanyService.deactivateCompany(id, { expected_version: company.version, transition_key: newKey() }); }, onSuccess: () => { toast.success('Company lifecycle updated'); void client.invalidateQueries({ queryKey: ['multi-company-company', id] }); void client.invalidateQueries({ queryKey: ['multi-company-companies'] }); }, onError: () => toast.error('The lifecycle command was not applied.') });
  if (!id) return MissingId(); if (query.isLoading) return <LoadingPage />; if (query.error || !query.data) return <PageScaffold title="Company" description="Company record"><GovernedError error={query.error} onRetry={() => void query.refetch()} /></PageScaffold>;
  const company = query.data.data;
  return <PageScaffold title={`${company.company_code} · ${company.company_name}`} description="A single view of identity, ownership, access, hierarchy, and safe lifecycle commands." actions={<><Button variant="outline" onClick={() => navigate(`${PATHS.companies}/${id}/access`)}><KeyRound className="mr-2 h-4 w-4" />Access</Button>{company.allowed_commands.includes('update') && <Button variant="outline" onClick={() => navigate(`${PATHS.companies}/${id}/edit`)}>Edit</Button>}{company.allowed_commands.includes('deactivate') && <Button variant="danger" onClick={() => setConfirm('deactivate')}>Deactivate</Button>}</>}>
    <BackButton to={PATHS.companies} label="All companies" /><Card><CardHeader><CardTitle>Legal entity profile</CardTitle></CardHeader><CardContent><DetailGrid entries={[[ 'Status', <StatusPill value={company.is_active ? 'active' : 'inactive'} /> ], ['Legal name', company.legal_name], ['Currency', company.currency], ['Fiscal year starts', `Month ${company.fiscal_year_start_month}`], ['Consolidation group', company.consolidation_group || 'Ungrouped'], ['Ownership', company.ownership_percentage ? `${company.ownership_percentage}%` : 'Not specified'], ['Parent', company.parent_company_name ?? 'Top-level company'], ['Holding company', company.is_holding ? 'Yes' : 'No'], ['Tax identifier', company.tax_id ?? 'Masked or unavailable'], ['Version', company.version], ['Last changed', new Date(company.updated_at).toLocaleString()], ['Support evidence', company.correlation_id]]} /></CardContent></Card>
    {Object.keys(company.denial_reasons).length > 0 && <Card><CardHeader><CardTitle>Command prerequisites</CardTitle></CardHeader><CardContent className="space-y-2">{Object.entries(company.denial_reasons).map(([commandName, reason]) => <InlineWarning key={commandName}><strong className="capitalize">{commandName.replaceAll('_', ' ')}:</strong> {reason.replaceAll('_', ' ')}</InlineWarning>)}</CardContent></Card>}
    <ConfirmDialog open={confirm !== null} onOpenChange={(open) => { if (!open) setConfirm(null); }} title={confirm === 'delete' ? 'Soft-delete this company?' : 'Deactivate this company?'} description="The server will verify pending financial work and protected history. No historical evidence will be destroyed." confirmLabel={command.isPending ? 'Applying…' : 'Apply lifecycle change'} variant="danger" onConfirm={() => { if (confirm) command.mutate(confirm); }} />
  </PageScaffold>;
}

interface CompanyFormState { company_code: string; company_name: string; legal_name: string; tax_id: string; currency: string; fiscal_year_start_month: string; parent_company: string; consolidation_group: string; ownership_percentage: string; address: string; is_holding: boolean }
const emptyCompany: CompanyFormState = { company_code: '', company_name: '', legal_name: '', tax_id: '', currency: 'USD', fiscal_year_start_month: '1', parent_company: '', consolidation_group: '', ownership_percentage: '', address: '', is_holding: false };
// Create/edit intentionally share validation, hydration, concurrency, and unsaved-change behavior.
// eslint-disable-next-line complexity
function CompanyFormPage({ edit }: { edit: boolean }) {
  const { id } = useParams(); const navigate = useNavigate(); const [form, setForm] = useState(emptyCompany); const [hydrated, setHydrated] = useState(false); const [submitted, setSubmitted] = useState(false); useUnsavedChanges(!submitted && Object.values(form).some((value) => value !== '' && value !== false) && (!edit || hydrated));
  const companyQuery = useQuery({ queryKey: ['multi-company-company', id], queryFn: () => multiCompanyService.getCompany(id!), enabled: edit && Boolean(id) });
  if (edit && companyQuery.data && !hydrated) { const c = companyQuery.data.data; setForm({ company_code: c.company_code, company_name: c.company_name, legal_name: c.legal_name, tax_id: c.tax_id ?? '', currency: c.currency, fiscal_year_start_month: String(c.fiscal_year_start_month), parent_company: c.parent_company ?? '', consolidation_group: c.consolidation_group, ownership_percentage: c.ownership_percentage ?? '', address: c.address, is_holding: c.is_holding }); setHydrated(true); }
  const mutation = useMutation({ mutationFn: async () => { const core = { company_code: form.company_code.trim().toUpperCase(), company_name: form.company_name.trim(), legal_name: form.legal_name.trim(), tax_id: form.tax_id.trim() || undefined, currency: form.currency.trim().toUpperCase(), fiscal_year_start_month: Number(form.fiscal_year_start_month), parent_company_id: form.parent_company || null, consolidation_group: form.consolidation_group.trim(), ownership_percentage: form.ownership_percentage || null, address: form.address.trim(), is_holding: form.is_holding }; if (edit) { if (!id || !companyQuery.data) throw new Error('Company unavailable'); return multiCompanyService.updateCompany(id, { ...core, expected_version: companyQuery.data.data.version }); } const body: CompanyCreateRequest = { ...core, idempotency_key: newKey() }; return multiCompanyService.createCompany(body); }, onSuccess: (result) => { setSubmitted(true); toast.success(edit ? 'Company updated' : 'Company created'); navigate(`${PATHS.companies}/${result.data.id}`); }, onError: () => toast.error('Review the highlighted values and try again.') });
  const submit = (event: FormEvent) => { event.preventDefault(); const month = Number(form.fiscal_year_start_month); if (!form.company_code.trim() || !form.company_name.trim() || !form.legal_name.trim() || !/^[A-Za-z]{3}$/.test(form.currency) || month < 1 || month > 12) { toast.error('Code, names, a 3-letter currency, and fiscal month 1–12 are required.'); return; } mutation.mutate(); };
  if (edit && companyQuery.isLoading) return <LoadingPage />; if (edit && (companyQuery.error || !companyQuery.data)) return <PageScaffold title="Edit company" description="Update legal entity"><GovernedError error={companyQuery.error} onRetry={() => void companyQuery.refetch()} /></PageScaffold>;
  const field = (key: keyof CompanyFormState, label: string, hint: string, type = 'text') => <div><Label htmlFor={`company-${key}`}>{label}</Label><Input id={`company-${key}`} type={type} className="mt-1" value={String(form[key])} onChange={(event) => setForm({ ...form, [key]: event.target.value })} aria-describedby={`company-${key}-hint`} /><p id={`company-${key}-hint`} className="mt-1 text-xs text-muted-foreground">{hint}</p></div>;
  return <PageScaffold title={edit ? 'Edit company' : 'Create company'} description="Start with legal identity and fiscal context. Ownership and hierarchy remain reversible and cycle-checked by the server."><BackButton to={edit && id ? `${PATHS.companies}/${id}` : PATHS.companies} /><form onSubmit={submit}><Card><CardHeader><CardTitle>Identity and reporting</CardTitle></CardHeader><CardContent className="grid gap-5 md:grid-cols-2">{field('company_code', 'Company code', 'Short unique identifier; normalized to uppercase.')}{field('company_name', 'Display name', 'Used throughout operational screens.')}{field('legal_name', 'Legal name', 'Required for contracts and statutory reporting.')}{field('currency', 'Functional currency', 'ISO 4217 code, for example USD or INR.')}{field('fiscal_year_start_month', 'Fiscal year start month', 'Safe range: 1 through 12.', 'number')}{field('parent_company', 'Parent company UUID', 'Leave blank for a top-level entity. The server rejects cycles and cross-tenant parents.')}{field('consolidation_group', 'Consolidation group', 'Companies in the same reporting group can be consolidated.')}{field('ownership_percentage', 'Ownership percentage', 'Optional safe range: 0.00 through 100.00.', 'number')}{field('tax_id', 'Tax identifier', 'Sensitive: visibility depends on read-sensitive permission.')}<div className="md:col-span-2"><Label htmlFor="company-address">Address</Label><Textarea id="company-address" className="mt-1" value={form.address} onChange={(event) => setForm({ ...form, address: event.target.value })} /></div><label className="flex items-center gap-2 text-sm"><input type="checkbox" checked={form.is_holding} onChange={(event) => setForm({ ...form, is_holding: event.target.checked })} />Holding company</label><div className="flex gap-2 md:col-span-2"><Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? 'Saving…' : edit ? 'Save new version' : 'Create company'}</Button><Button type="button" variant="outline" onClick={() => navigate(PATHS.companies)}>Cancel</Button></div></CardContent></Card></form></PageScaffold>;
}
export function CreateCompanyPage() { return <CompanyFormPage edit={false} />; }
export function EditCompanyPage() { return <CompanyFormPage edit />; }

export function CompanyHierarchyPage() {
  const query = useQuery({ queryKey: ['multi-company-hierarchy'], queryFn: () => multiCompanyService.getHierarchy() });
  const render = (nodes: readonly CompanyHierarchyNode[]): ReactNode => <ul className="space-y-3">{nodes.map((node) => <li key={node.id} className="rounded-lg border border-border bg-card p-4"><Link className="font-medium text-primary hover:underline" to={`${PATHS.companies}/${node.id}`}>{node.company_name}</Link><span className="ml-2 text-xs text-muted-foreground">{node.company_code} · {node.is_active ? 'Active' : 'Inactive'}</span>{node.children.length > 0 && <div className="ml-6 mt-3 border-l border-border pl-4">{render(node.children)}</div>}</li>)}</ul>;
  if (query.isLoading) return <LoadingPage />; return <PageScaffold title="Company hierarchy" description="Explore ownership paths and reporting groups. The hierarchy is bounded and cycle-safe.">{query.error || !query.data ? <GovernedError error={query.error} onRetry={() => void query.refetch()} /> : query.data.data.length ? render(query.data.data) : <EmptyState icon={GitBranch} title="No hierarchy yet" description="Create a company and assign parent relationships to build your group." action={{ label: 'Create company', onClick: () => location.assign(`${PATHS.companies}/new`) }} />}</PageScaffold>;
}

export function CompanyAccessPage() {
  const { id } = useParams(); const client = useQueryClient(); const [subject, setSubject] = useState(''); const [role, setRole] = useState<CompanyRole>('viewer'); const [revoke, setRevoke] = useState<UUID | null>(null);
  const query = useQuery({ queryKey: ['multi-company-access', id], queryFn: () => multiCompanyService.listAccessGrants({ company_id: id, page_size: 100 }), enabled: Boolean(id) });
  const grant = useMutation({ mutationFn: () => { if (!id) throw new Error('Company unavailable'); return multiCompanyService.grantAccess({ company_id: id, subject_id: subject.trim(), role, valid_from: new Date().toISOString() }); }, onSuccess: () => { setSubject(''); toast.success('Company access granted'); void client.invalidateQueries({ queryKey: ['multi-company-access', id] }); }, onError: () => toast.error('Access was not granted.') });
  const revokeMutation = useMutation({ mutationFn: (grantId: UUID) => multiCompanyService.revokeAccess(grantId, 'Revoked by an administrator from the company access workspace'), onSuccess: () => { toast.success('Access revoked with audit evidence'); void client.invalidateQueries({ queryKey: ['multi-company-access', id] }); }, onError: () => toast.error('Access was not revoked.') });
  if (!id) return MissingId(); if (query.isLoading) return <LoadingPage />;
  return <PageScaffold title="Company access" description="Grant the narrowest company role required. Tenant permissions remain a separate, deny-by-default control." actions={<BackButton to={`${PATHS.companies}/${id}`} label="Company" />}>
    <Card><CardHeader><CardTitle>Grant access</CardTitle></CardHeader><CardContent><form className="grid gap-4 md:grid-cols-[1fr_220px_auto]" onSubmit={(event) => { event.preventDefault(); if (!subject.trim()) { toast.error('Subject ID is required'); return; } grant.mutate(); }}><div><Label htmlFor="access-subject">Subject identifier</Label><Input id="access-subject" value={subject} onChange={(event) => setSubject(event.target.value)} placeholder="User or service subject" /></div><div><Label htmlFor="access-role">Company role</Label><select id="access-role" value={role} onChange={(event) => setRole(event.target.value as CompanyRole)} className="mt-1 h-10 w-full rounded-md border border-input bg-background px-3 text-sm">{(['viewer','operator','approver','controller','tax_admin'] as const).map((item) => <option key={item} value={item}>{item.replaceAll('_', ' ')}</option>)}</select></div><Button className="self-end" type="submit" disabled={grant.isPending}><ShieldCheck className="mr-2 h-4 w-4" />{grant.isPending ? 'Granting…' : 'Grant access'}</Button></form></CardContent></Card>
    {query.error || !query.data ? <GovernedError error={query.error} onRetry={() => void query.refetch()} /> : !query.data.data.length ? <EmptyState icon={KeyRound} title="No direct grants" description="Company operations remain unavailable until an authorized policy or direct grant provides scope." /> : <Card className="overflow-hidden"><div className="overflow-x-auto"><table className="w-full min-w-[640px] text-sm"><thead className="border-b border-border bg-muted"><tr><th className="p-4 text-left">Subject</th><th className="p-4 text-left">Role</th><th className="p-4 text-left">Valid window</th><th className="p-4 text-right">Action</th></tr></thead><tbody>{query.data.data.map((item) => <tr key={item.id} className="border-b border-border"><td className="p-4 font-medium">{item.subject_id}</td><td className="p-4"><StatusPill value={item.role} /></td><td className="p-4 text-muted-foreground">{new Date(item.valid_from).toLocaleString()} – {item.valid_until ? new Date(item.valid_until).toLocaleString() : 'No expiry'}</td><td className="p-4 text-right"><Button size="sm" variant="outline" disabled={Boolean(item.revoked_at)} onClick={() => setRevoke(item.id)}>{item.revoked_at ? 'Revoked' : 'Revoke'}</Button></td></tr>)}</tbody></table></div></Card>}
    <ConfirmDialog open={revoke !== null} onOpenChange={(open) => { if (!open) setRevoke(null); }} title="Revoke company access?" description="The grant will be retained as immutable audit history, but it will stop authorizing new operations." confirmLabel={revokeMutation.isPending ? 'Revoking…' : 'Revoke access'} variant="danger" onConfirm={() => { if (revoke) revokeMutation.mutate(revoke); }} />
  </PageScaffold>;
}

export function TransactionListPage() {
  return <ResourceList<IntercompanyTransaction> title="Intercompany transactions" description="Track reciprocal activity from draft through dual approval, posting, reconciliation, and elimination." queryKey="multi-company-transactions" load={(filters) => multiCompanyService.listTransactions(filters)} createPath={`${PATHS.transactions}/new`} createLabel="New transaction" emptyTitle="Record the first intercompany transaction" emptyDescription="Choose both companies and see the reciprocal accounting impact before submitting." columns={[
    { label: 'Reference', render: (item) => <Link className="font-medium text-primary hover:underline" to={`${PATHS.transactions}/${item.id}`}>{item.reference}</Link> },
    { label: 'Companies', render: (item) => <span>{item.source_company_name ?? item.source_company}<span className="mx-2 text-muted-foreground">→</span>{item.target_company_name ?? item.target_company}</span> },
    { label: 'Type', render: (item) => item.transaction_type.replaceAll('_', ' ') }, { label: 'Amount', render: (item) => `${item.currency} ${item.amount}` }, { label: 'Status', render: (item) => <StatusPill value={item.status} /> },
  ]} />;
}

// The financial detail surface deliberately composes state, evidence, approvals, and commands.
// eslint-disable-next-line complexity
export function TransactionDetailPage() {
  const { id } = useParams(); const client = useQueryClient(); const [dialog, setDialog] = useState<'submit' | 'post' | 'cancel' | null>(null);
  const query = useQuery({ queryKey: ['multi-company-transaction', id], queryFn: () => multiCompanyService.getTransaction(id!), enabled: Boolean(id), refetchInterval: (current) => ['posting'].includes(current.state.data?.data.status ?? '') ? 3000 : false });
  const command = useMutation({ mutationFn: async (name: 'submit' | 'post' | 'cancel') => { if (!id || !query.data) throw new Error('Transaction unavailable'); const body = { expected_version: query.data.data.version, transition_key: newKey() }; if (name === 'submit') return multiCompanyService.submitTransaction(id, body); if (name === 'post') return multiCompanyService.postTransaction(id, body, newKey()); return multiCompanyService.cancelTransaction(id, { ...body, reason: 'Cancelled by operator after reviewing downstream impact' }); }, onSuccess: () => { toast.success('Transaction command accepted'); void client.invalidateQueries({ queryKey: ['multi-company-transaction', id] }); }, onError: () => toast.error('The transaction command was not applied.') });
  if (!id) return MissingId(); if (query.isLoading) return <LoadingPage />; if (query.error || !query.data) return <PageScaffold title="Transaction" description="Transaction evidence"><GovernedError error={query.error} onRetry={() => void query.refetch()} /></PageScaffold>;
  const item = query.data.data;
  return <PageScaffold title={item.reference} description="Approval evidence, pricing, journals, and transition history remain visible on one surface." actions={<>{item.allowed_commands.includes('update') && <Button variant="outline" onClick={() => location.assign(`${PATHS.transactions}/${id}/edit`)}>Edit draft</Button>}{item.allowed_commands.includes('submit') && <Button onClick={() => setDialog('submit')}>Submit</Button>}{item.allowed_commands.includes('post') && <Button onClick={() => setDialog('post')}>Post to ledgers</Button>}{item.allowed_commands.includes('cancel') && <Button variant="danger" onClick={() => setDialog('cancel')}>Cancel</Button>}</>}>
    <BackButton to={PATHS.transactions} label="All transactions" /><div className="grid gap-6 xl:grid-cols-3"><Card className="xl:col-span-2"><CardHeader><CardTitle>Reciprocal entry</CardTitle></CardHeader><CardContent><DetailGrid entries={[[ 'Status', <StatusPill value={item.status} /> ], ['Source company', item.source_company_name ?? item.source_company], ['Target company', item.target_company_name ?? item.target_company], ['Transaction type', item.transaction_type.replaceAll('_', ' ')], ['Original amount', `${item.currency} ${item.original_amount}`], ['Priced amount', `${item.currency} ${item.amount}`], ['Target amount', item.target_amount ?? 'Pending conversion'], ['Transaction date', item.transaction_date], ['Source journal', item.source_journal_id ?? 'Not posted'], ['Target journal', item.target_journal_id ?? 'Not posted'], ['Job', item.job_id ?? 'No active job'], ['Support evidence', item.correlation_id]]} /></CardContent></Card><Card><CardHeader><CardTitle>Dual approval</CardTitle></CardHeader><CardContent className="space-y-3">{(['source','target'] as const).map((side) => { const approval = item.approvals.find((entry) => entry.side === side && entry.decision === 'approved'); return <div key={side} className="flex items-center justify-between rounded-lg border border-border p-3"><span className="capitalize">{side} company</span>{approval ? <span className="flex items-center gap-1 text-sm"><CheckCircle2 className="h-4 w-4" />Approved</span> : <StatusPill value="pending" />}</div>; })}</CardContent></Card></div>
    <Card><CardHeader><CardTitle>State timeline</CardTitle></CardHeader><CardContent>{!item.transition_history.length ? <p className="text-sm text-muted-foreground">This transaction is still in its initial draft state.</p> : <ol className="space-y-4 border-l border-border pl-5">{item.transition_history.map((step, index) => <li key={`${step.occurred_at}:${index}`}><p className="font-medium capitalize">{step.command.replaceAll('_',' ')} · {step.from_status} → {step.to_status}</p><p className="text-xs text-muted-foreground">{new Date(step.occurred_at).toLocaleString()} · {step.actor_id} · {step.correlation_id}</p></li>)}</ol>}</CardContent></Card>
    {item.failure_code && <InlineWarning><strong>{item.failure_code}</strong>: {item.failure_detail} Journal compensation evidence is retained; retry only after resolving the prerequisite.</InlineWarning>}
    <ConfirmDialog open={dialog !== null} onOpenChange={(open) => { if (!open) setDialog(null); }} title={`${dialog === 'post' ? 'Post' : dialog === 'cancel' ? 'Cancel' : 'Submit'} transaction?`} description={dialog === 'post' ? 'This creates durable posting work for both company ledgers. Partial failure triggers compensation and never reports success.' : dialog === 'submit' ? 'Both company approvers must authorize the transaction before posting.' : 'Cancellation is retained in immutable transition history.'} confirmLabel={command.isPending ? 'Applying…' : 'Confirm command'} variant={dialog === 'cancel' ? 'danger' : 'default'} onConfirm={() => { if (dialog) command.mutate(dialog); }} />
  </PageScaffold>;
}

interface TransactionFormState { reference: string; source_company: string; target_company: string; transaction_type: TransactionType; product_category: string; original_amount: string; amount: string; currency: string; exchange_rate: string; target_amount: string; transaction_date: string; description: string }
const emptyTransaction: TransactionFormState = { reference: '', source_company: '', target_company: '', transaction_type: 'sale', product_category: '', original_amount: '', amount: '', currency: 'USD', exchange_rate: '', target_amount: '', transaction_date: new Date().toISOString().slice(0, 10), description: '' };
// Create/edit intentionally share reciprocal-entry validation and concurrency behavior.
// eslint-disable-next-line complexity
function TransactionFormPage({ edit }: { edit: boolean }) {
  const { id } = useParams(); const navigate = useNavigate(); const [form, setForm] = useState(emptyTransaction); const [hydrated, setHydrated] = useState(false); const [submitted, setSubmitted] = useState(false); useUnsavedChanges(!submitted && Object.values(form).some(Boolean));
  const current = useQuery({ queryKey: ['multi-company-transaction', id], queryFn: () => multiCompanyService.getTransaction(id!), enabled: edit && Boolean(id) });
  if (edit && current.data && !hydrated) { const t = current.data.data; setForm({ reference: t.reference, source_company: t.source_company, target_company: t.target_company, transaction_type: t.transaction_type, product_category: t.product_category, original_amount: t.original_amount, amount: t.amount, currency: t.currency, exchange_rate: t.exchange_rate ?? '', target_amount: t.target_amount ?? '', transaction_date: t.transaction_date, description: t.description }); setHydrated(true); }
  const mutation = useMutation({ mutationFn: () => { const body = { reference: form.reference, transaction_type: form.transaction_type, product_category: form.product_category, amount: form.amount, currency: form.currency, exchange_rate: form.exchange_rate || null, description: form.description, transaction_date: form.transaction_date }; if (edit) { if (!id || !current.data) throw new Error('Transaction unavailable'); return multiCompanyService.updateTransaction(id, { ...body, expected_version: current.data.data.version }); } return multiCompanyService.createTransaction({ ...body, source_company_id: form.source_company, target_company_id: form.target_company, idempotency_key: newKey() }); }, onSuccess: (result) => { setSubmitted(true); toast.success(edit ? 'Draft updated' : 'Transaction draft created'); navigate(`${PATHS.transactions}/${result.data.id}`); }, onError: () => toast.error('The transaction draft could not be saved.') });
  if (edit && current.isLoading) return <LoadingPage />; if (edit && (current.error || !current.data)) return <PageScaffold title="Edit transaction" description="Draft transaction"><GovernedError error={current.error} onRetry={() => void current.refetch()} /></PageScaffold>;
  const input = (key: keyof TransactionFormState, label: string, hint: string, type = 'text') => <div><Label htmlFor={`transaction-${key}`}>{label}</Label><Input id={`transaction-${key}`} type={type} value={form[key]} onChange={(event) => setForm({ ...form, [key]: event.target.value })} /><p className="mt-1 text-xs text-muted-foreground">{hint}</p></div>;
  return <PageScaffold title={edit ? 'Edit transaction draft' : 'Create intercompany transaction'} description="See both company sides and conversion impact before committing the draft."><BackButton to={edit && id ? `${PATHS.transactions}/${id}` : PATHS.transactions} /><form onSubmit={(event) => { event.preventDefault(); if (!form.reference.trim() || form.source_company === form.target_company || Number(form.amount) <= 0) { toast.error('Reference, different companies, and a positive amount are required.'); return; } mutation.mutate(); }}><Card><CardHeader><CardTitle>Reciprocal transaction</CardTitle></CardHeader><CardContent className="grid gap-5 md:grid-cols-2">{input('reference','Reference','Unique tenant reference.')}{input('transaction_date','Transaction date','The effective date used for pricing and FX.','date')}{input('source_company','Source company UUID','Requires an applicable company access grant.')}{input('target_company','Target company UUID','Must differ from the source company.')}<div><Label htmlFor="transaction-type">Transaction type</Label><select id="transaction-type" value={form.transaction_type} onChange={(event) => setForm({ ...form, transaction_type: event.target.value as TransactionType })} className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm">{(['sale','purchase','service','loan','transfer','dividend','cost_allocation'] as const).map((type) => <option key={type} value={type}>{type.replaceAll('_',' ')}</option>)}</select></div>{input('product_category','Product category','Used to resolve the effective transfer-pricing rule.')}{input('original_amount','Original amount','Positive decimal amount.','number')}{input('amount','Priced amount','The server checks configured currency limits.','number')}{input('currency','Currency','ISO 4217 functional currency.')}{input('exchange_rate','Exchange rate','Optional rate from source currency to target currency.','number')}{input('target_amount','Target amount','Preview of the reciprocal company impact.','number')}<div className="md:col-span-2"><Label htmlFor="transaction-description">Description</Label><Textarea id="transaction-description" value={form.description} onChange={(event) => setForm({ ...form, description: event.target.value })} /></div><InlineWarning>Draft creation does not post journals. Submission requires independent source and target approval; posting uses a durable idempotent job.</InlineWarning><div className="flex gap-2 self-end"><Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? 'Saving…' : 'Save draft'}</Button><Button type="button" variant="outline" onClick={() => navigate(PATHS.transactions)}>Cancel</Button></div></CardContent></Card></form></PageScaffold>;
}
export function CreateTransactionPage() { return <TransactionFormPage edit={false} />; }
export function EditTransactionPage() { return <TransactionFormPage edit />; }

