// The detail surface coordinates readiness, jobs, evidence, and financial commands.
// eslint-disable-next-line complexity
export function ConsolidationRunDetailPage() {
  const { id } = useParams(); const client = useQueryClient(); const [dialog, setDialog] = useState<'execute' | 'approve' | 'publish' | null>(null);
  const query = useQuery({ queryKey: ['multi-company-consolidation', id], queryFn: () => multiCompanyService.getConsolidation(id!), enabled: Boolean(id), refetchInterval: (current) => ['queued','running'].includes(current.state.data?.data.status ?? '') ? 3000 : false });
  const command = useMutation({ mutationFn: async (name: 'execute' | 'approve' | 'publish') => { if (!id || !query.data) throw new Error('Run unavailable'); const body = { expected_version: query.data.data.version, transition_key: newKey() }; if (name === 'execute') return multiCompanyService.executeConsolidation(id, body, newKey()); if (name === 'approve') return multiCompanyService.approveConsolidation(id, body); return multiCompanyService.publishConsolidation(id, body); }, onSuccess: () => { toast.success('Consolidation command accepted'); void client.invalidateQueries({ queryKey: ['multi-company-consolidation', id] }); }, onError: () => toast.error('The consolidation command was not applied.') });
  if (!id) return MissingId(); if (query.isLoading) return <LoadingPage />; if (query.error || !query.data) return <PageScaffold title="Consolidation" description="Consolidation run"><GovernedError error={query.error} onRetry={() => void query.refetch()} /></PageScaffold>;
  const run = query.data.data;
  return <PageScaffold title={run.name} description="Readiness, elimination evidence, execution progress, and final reporting remain traceable here." actions={<>{run.allowed_commands.includes('update') && <Button variant="outline" onClick={() => location.assign(`${PATHS.consolidations}/${id}/edit`)}>Edit</Button>}{run.allowed_commands.includes('execute') && <Button onClick={() => setDialog('execute')}>Execute</Button>}{run.allowed_commands.includes('approve') && <Button onClick={() => setDialog('approve')}>Approve</Button>}{run.allowed_commands.includes('publish') && <Button onClick={() => setDialog('publish')}>Publish</Button>}</>}>
    <BackButton to={PATHS.consolidations} label="All consolidations" /><div className="grid gap-6 lg:grid-cols-3"><Card className="lg:col-span-2"><CardHeader><CardTitle>Group snapshot</CardTitle></CardHeader><CardContent><DetailGrid entries={[[ 'Status', <StatusPill value={run.status} /> ], ['Group', run.consolidation_group], ['Period', `${run.period_start} – ${run.period_end}`], ['Reporting currency', run.reporting_currency], ['Translation', run.translation_method.replaceAll('_',' ')], ['Included companies', run.total_companies], ['Eliminations', run.total_eliminations], ['Elimination total', run.elimination_total], ['Minority interest', run.minority_interest_total], ['Job progress', run.job_id ?? 'Not queued'], ['Failed step', run.failure_step || 'None'], ['Support evidence', run.correlation_id]]} /></CardContent></Card><Card><CardHeader><CardTitle>Evidence</CardTitle></CardHeader><CardContent className="space-y-3"><Button variant="outline" className="w-full" onClick={() => location.assign(`${PATHS.consolidations}/${id}/eliminations`)}>Review eliminations</Button>{run.report_snapshot && <div className="rounded-lg border border-border p-3 text-sm"><p className="font-medium">Elimination total</p><p className="mt-1 text-xl">{run.reporting_currency} {run.report_snapshot.elimination_total}</p><StatusPill value="reconciled" /></div>}</CardContent></Card></div>
    {run.failure_code && <InlineWarning><strong>{run.failure_code}</strong> at {run.failure_step}: {run.failure_detail}. Resolve the missing dependency before retrying.</InlineWarning>}
    <ConfirmDialog open={dialog !== null} onOpenChange={(open) => { if (!open) setDialog(null); }} title={`${dialog ?? ''} consolidation?`} description={dialog === 'execute' ? 'This queues durable work after validating period closure, currency coverage, overlap, company count, and minority interest.' : 'Separation of duties and final reconciliation are checked server-side before this financial command is accepted.'} confirmLabel={command.isPending ? 'Applying…' : 'Confirm command'} onConfirm={() => { if (dialog) command.mutate(dialog); }} />
  </PageScaffold>;
}

interface ConsolidationFormState { name: string; consolidation_group: string; period_start: string; period_end: string; reporting_currency: string; translation_method: TranslationMethod }
const emptyConsolidation: ConsolidationFormState = { name: '', consolidation_group: '', period_start: '', period_end: '', reporting_currency: 'USD', translation_method: 'current_rate' };
function ConsolidationFormPage({ edit }: { edit: boolean }) {
  const { id } = useParams(); const navigate = useNavigate(); const [form, setForm] = useState(emptyConsolidation); const [hydrated, setHydrated] = useState(false); const current = useQuery({ queryKey: ['multi-company-consolidation', id], queryFn: () => multiCompanyService.getConsolidation(id!), enabled: edit && Boolean(id) });
  if (edit && current.data && !hydrated) { const r = current.data.data; setForm({ name: r.name, consolidation_group: r.consolidation_group, period_start: r.period_start, period_end: r.period_end, reporting_currency: r.reporting_currency, translation_method: r.translation_method }); setHydrated(true); }
  useUnsavedChanges(Object.values(form).some(Boolean)); const mutation = useMutation({ mutationFn: () => edit && id && current.data ? multiCompanyService.updateConsolidation(id, { ...form, expected_version: current.data.data.version }) : multiCompanyService.createConsolidation({ ...form, idempotency_key: newKey() }), onSuccess: (result) => { toast.success('Consolidation draft saved'); navigate(`${PATHS.consolidations}/${result.data.id}`); }, onError: () => toast.error('The consolidation draft could not be saved.') });
  if (edit && current.isLoading) return <LoadingPage />;
  return <PageScaffold title={edit ? 'Edit consolidation' : 'Create consolidation'} description="Preview the reporting boundary and readiness dependencies before durable execution."><BackButton to={PATHS.consolidations} /><form onSubmit={(event) => { event.preventDefault(); if (!form.name || !form.consolidation_group || !form.period_start || !form.period_end || form.period_start > form.period_end) { toast.error('Name, group, and a valid period are required.'); return; } mutation.mutate(); }}><Card><CardContent className="grid gap-5 p-6 md:grid-cols-2"><div><Label htmlFor="run-name">Run name</Label><Input id="run-name" value={form.name} onChange={(event) => setForm({ ...form, name: event.target.value })} /></div><div><Label htmlFor="run-group">Consolidation group</Label><Input id="run-group" value={form.consolidation_group} onChange={(event) => setForm({ ...form, consolidation_group: event.target.value })} /></div><div><Label htmlFor="run-start">Period start</Label><Input id="run-start" type="date" value={form.period_start} onChange={(event) => setForm({ ...form, period_start: event.target.value })} /></div><div><Label htmlFor="run-end">Period end</Label><Input id="run-end" type="date" value={form.period_end} onChange={(event) => setForm({ ...form, period_end: event.target.value })} /></div><div><Label htmlFor="run-currency">Reporting currency</Label><Input id="run-currency" value={form.reporting_currency} maxLength={3} onChange={(event) => setForm({ ...form, reporting_currency: event.target.value.toUpperCase() })} /></div><div><Label htmlFor="run-method">Translation method</Label><select id="run-method" value={form.translation_method} onChange={(event) => setForm({ ...form, translation_method: event.target.value as TranslationMethod })} className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm">{(['current_rate','temporal','monetary_non_monetary'] as const).map((method) => <option key={method} value={method}>{method.replaceAll('_',' ')}</option>)}</select></div><div className="md:col-span-2"><InlineWarning>Execution remains disabled until the server verifies at least the configured company count, closed accounting periods, FX coverage, no forbidden overlap, and balanced eliminations.</InlineWarning></div><div className="flex gap-2"><Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? 'Saving…' : 'Save draft'}</Button><Button type="button" variant="outline" onClick={() => navigate(PATHS.consolidations)}>Cancel</Button></div></CardContent></Card></form></PageScaffold>;
}
