export function TransferPricingRuleDetailPage() {
  const { id } = useParams(); const query = useQuery({ queryKey: ['multi-company-pricing-rule', id], queryFn: () => multiCompanyService.getTransferPricingRule(id!), enabled: Boolean(id) }); if (!id) return MissingId(); if (query.isLoading) return <LoadingPage />; if (query.error || !query.data) return <PageScaffold title="Pricing rule" description="Versioned pricing evidence"><GovernedError error={query.error} onRetry={() => void query.refetch()} /></PageScaffold>; const rule = query.data.data;
  return <PageScaffold title={`${rule.name} · v${rule.rule_version}`} description="Historical transactions retain this exact rule version and calculation snapshot." actions={rule.allowed_commands.includes('update') && <Button onClick={() => location.assign(`${PATHS.pricing}/${id}/edit`)}>Create new version</Button>}><BackButton to={PATHS.pricing} /><Card><CardContent className="p-6"><DetailGrid entries={[[ 'Status', <StatusPill value={rule.is_active ? 'active' : 'inactive'} />], ['Method', rule.pricing_method.replaceAll('_',' ')], ['Transaction type', rule.transaction_type], ['Product category', rule.product_category], ['Source company', rule.source_company], ['Target company', rule.target_company], ['Markup', rule.markup_percentage ? `${rule.markup_percentage}%` : 'Method-specific'], ['Margin range', `${rule.margin_range_min ?? '—'} to ${rule.margin_range_max ?? '—'}`], ['Effective', `${rule.effective_from} – ${rule.effective_to ?? 'ongoing'}`], ['Supersedes', rule.supersedes ?? 'Initial version'], ['Documentation', rule.documentation || 'No additional documentation'], ['Support evidence', rule.correlation_id]]} /></CardContent></Card></PageScaffold>;
}
interface PricingFormState { name: string; source_company: string; target_company: string; product_category: string; transaction_type: TransactionType; pricing_method: PricingMethod; extension_key: string; markup_percentage: string; margin_range_min: string; margin_range_max: string; effective_from: string; effective_to: string; documentation: string }
const emptyPricing: PricingFormState = { name: '', source_company: '', target_company: '', product_category: '', transaction_type: 'sale', pricing_method: 'cost_plus', extension_key: '', markup_percentage: '', margin_range_min: '', margin_range_max: '', effective_from: new Date().toISOString().slice(0,10), effective_to: '', documentation: '' };
function PricingFormPage({ edit }: { edit: boolean }) {
  const { id } = useParams(); const navigate = useNavigate(); const [form, setForm] = useState(emptyPricing); const [hydrated, setHydrated] = useState(false); const current = useQuery({ queryKey: ['multi-company-pricing-rule', id], queryFn: () => multiCompanyService.getTransferPricingRule(id!), enabled: edit && Boolean(id) });
  if (edit && current.data && !hydrated) { const r = current.data.data; setForm({ name: r.name, source_company: r.source_company, target_company: r.target_company, product_category: r.product_category, transaction_type: r.transaction_type, pricing_method: r.pricing_method, extension_key: r.extension_key, markup_percentage: r.markup_percentage ?? '', margin_range_min: r.margin_range_min ?? '', margin_range_max: r.margin_range_max ?? '', effective_from: r.effective_from, effective_to: r.effective_to ?? '', documentation: r.documentation }); setHydrated(true); }
  useUnsavedChanges(Object.values(form).some(Boolean)); const mutation = useMutation({ mutationFn: () => { const body = { name: form.name, product_category: form.product_category, transaction_type: form.transaction_type, pricing_method: form.pricing_method, extension_key: form.pricing_method === 'extension' ? form.extension_key : undefined, markup_percentage: form.markup_percentage || null, margin_range_min: form.margin_range_min || null, margin_range_max: form.margin_range_max || null, effective_from: form.effective_from, effective_to: form.effective_to || null, documentation: form.documentation, parameters: form.pricing_method === 'cost_plus' ? { base_cost: '0' } : {} }; return edit && id && current.data ? multiCompanyService.updateTransferPricingRule(id, { ...body, expected_version: current.data.data.version }) : multiCompanyService.createTransferPricingRule({ ...body, source_company_id: form.source_company, target_company_id: form.target_company, idempotency_key: newKey() }); }, onSuccess: (result) => { toast.success(edit ? 'New pricing-rule version created' : 'Pricing rule created'); navigate(`${PATHS.pricing}/${result.data.id}`); }, onError: () => toast.error('The pricing rule could not be saved.') }); if (edit && current.isLoading) return <LoadingPage />;
  const field = (key: keyof PricingFormState, label: string, type = 'text') => <div><Label htmlFor={`pricing-${key}`}>{label}</Label><Input id={`pricing-${key}`} type={type} value={form[key]} onChange={(event) => setForm({ ...form, [key]: event.target.value })} /></div>;
  return <PageScaffold title={edit ? 'Create pricing-rule version' : 'Create transfer-pricing rule'} description="Configure a dated rule and preserve its formula evidence on every transaction."><BackButton to={PATHS.pricing} /><form onSubmit={(event) => { event.preventDefault(); if (!form.name || form.source_company === form.target_company || (form.pricing_method === 'cost_plus' && form.markup_percentage === '') || (form.pricing_method === 'extension' && !form.extension_key)) { toast.error('Name, different companies, and method-specific inputs are required.'); return; } mutation.mutate(); }}><Card><CardContent className="grid gap-5 p-6 md:grid-cols-2">{field('name','Rule name')}{field('product_category','Product category')}{field('source_company','Source company UUID')}{field('target_company','Target company UUID')}<div><Label htmlFor="pricing-method">Pricing method</Label><select id="pricing-method" value={form.pricing_method} onChange={(event) => setForm({ ...form, pricing_method: event.target.value as PricingMethod })} className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm">{(['cost_plus','resale_minus','comparable_uncontrolled','transactional_net_margin','profit_split','extension'] as const).map((method) => <option key={method} value={method}>{method.replaceAll('_',' ')}</option>)}</select></div><div><Label htmlFor="pricing-transaction-type">Transaction type</Label><select id="pricing-transaction-type" value={form.transaction_type} onChange={(event) => setForm({ ...form, transaction_type: event.target.value as TransactionType })} className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm">{(['sale','purchase','service','loan','transfer','dividend','cost_allocation'] as const).map((type) => <option key={type} value={type}>{type.replaceAll('_',' ')}</option>)}</select></div>{form.pricing_method === 'extension' ? field('extension_key','Governed extension key') : field('markup_percentage','Markup percentage','number')}{field('margin_range_min','Minimum margin','number')}{field('margin_range_max','Maximum margin','number')}{field('effective_from','Effective from','date')}{field('effective_to','Effective to','date')}<div className="md:col-span-2"><Label htmlFor="pricing-docs">Documentation</Label><Textarea id="pricing-docs" value={form.documentation} onChange={(event) => setForm({ ...form, documentation: event.target.value })} /></div><InlineWarning>Editing creates a new immutable version. Existing transaction snapshots continue to reference their original version.</InlineWarning><Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? 'Saving…' : 'Save rule version'}</Button></CardContent></Card></form></PageScaffold>;
}
export function CreateTransferPricingRulePage() { return <PricingFormPage edit={false} />; }
export function EditTransferPricingRulePage() { return <PricingFormPage edit />; }

export function TransferPricingSimulatorPage() {
  const [form, setForm] = useState({ source_company: '', target_company: '', product_category: '', transaction_type: 'sale' as TransactionType, amount: '', currency: 'USD', effective_date: new Date().toISOString().slice(0,10) }); const preview = useMutation({ mutationFn: () => multiCompanyService.previewTransferPrices({ source_company_id: form.source_company, target_company_id: form.target_company, product_category: form.product_category, transaction_type: form.transaction_type, amount: form.amount, currency: form.currency, effective_date: form.effective_date, scenarios: [{ method: 'cost_plus', amount: form.amount, parameters: {} }] }), onError: () => toast.error('Pricing preview is unavailable. No transaction was changed.') });
  return <PageScaffold title="Transfer-pricing simulator" description="Compare configured and entitled extension methods without mutating a transaction."><BackButton to={PATHS.pricing} /><div className="grid gap-6 lg:grid-cols-2"><Card><CardHeader><CardTitle>Scenario inputs</CardTitle></CardHeader><CardContent><form className="space-y-4" onSubmit={(event) => { event.preventDefault(); if (!form.source_company || form.source_company === form.target_company || Number(form.amount) <= 0) { toast.error('Choose different companies and a positive amount.'); return; } preview.mutate(); }}>{(['source_company','target_company','product_category','amount','currency','effective_date'] as const).map((key) => <div key={key}><Label htmlFor={`sim-${key}`}>{key.replaceAll('_',' ')}</Label><Input id={`sim-${key}`} type={key === 'amount' ? 'number' : key === 'effective_date' ? 'date' : 'text'} value={form[key]} onChange={(event) => setForm({ ...form, [key]: event.target.value })} /></div>)}<Button type="submit" disabled={preview.isPending}><Calculator className="mr-2 h-4 w-4" />{preview.isPending ? 'Calculating…' : 'Compare methods'}</Button></form></CardContent></Card><Card><CardHeader><CardTitle>Calculation evidence</CardTitle></CardHeader><CardContent>{preview.error ? <GovernedError error={preview.error} onRetry={() => preview.mutate()} /> : !preview.data ? <div className="flex min-h-72 flex-col items-center justify-center text-center text-muted-foreground"><CircleDollarSign className="mb-3 h-10 w-10" /><p>Enter a scenario to see formula, selected rule version, margin range, and rounding.</p></div> : <div className="space-y-3">{preview.data.data.map((result, index) => <div key={`${result.pricing_method}:${index}`} className="rounded-lg border border-border p-4"><p className="text-2xl font-semibold">{form.currency} {result.amount}</p><StatusPill value={result.pricing_method} /><div className="mt-3 rounded-lg bg-muted p-3 font-mono text-sm">{result.formula}</div><p className="mt-2 text-xs text-muted-foreground">Rule version {result.rule_version ?? 'not configured'} · {result.rounding_mode} · {result.precision} decimals</p></div>)}</div>}</CardContent></Card></div></PageScaffold>;
}

const defaultSettings: MultiCompanySettings = { draft_expiry_hours: 168, minimum_consolidation_company_count: 2, permitted_translation_methods: ['current_rate','temporal','monetary_non_monetary'], permitted_transaction_types: ['sale','purchase','service','loan','transfer','dividend','cost_allocation'], permitted_pricing_methods: ['cost_plus'], maximum_transaction_amount_by_currency: { USD: '1000000.00' }, approval_sides: ['source','target'], transfer_pricing_tolerance_min: '-5.0000', transfer_pricing_tolerance_max: '5.0000', allow_consolidation_overlap: false, rounding_mode: 'ROUND_HALF_EVEN', money_precision: 4, feature_flags: { core_transactions: true }, rollout: { roles: [], cohorts: [] }, extension_enablement_keys: [], notification_policy: { approval: true, dispute: true, failure: true, completion: true }, job_max_retries: 3, job_timeout_seconds: 300, default_currency: 'USD', default_fiscal_year_start_month: 1, ledger_accounts: { intercompany_receivable: 'INTERCO-AR', intercompany_payable: 'INTERCO-AP', intercompany_revenue: 'INTERCO-REV', intercompany_expense: 'INTERCO-EXP' }, elimination_accounts: { debit: 'INTERCO-DEBIT', credit: 'INTERCO-CREDIT' } };

export function ConfigurationVersionListPage() {
  const [environment, setEnvironment] = useState<RuntimeEnvironment>('development'); const [importError, setImportError] = useState(''); const client = useQueryClient(); const importMutation = useMutation({ mutationFn: (document: string) => multiCompanyService.importConfiguration(JSON.parse(document) as never), onSuccess: () => { toast.success('Configuration imported as an inactive draft'); void client.invalidateQueries({ queryKey: ['multi-company-configurations'] }); }, onError: () => setImportError('The document was rejected. Verify its signature and schema version.') });
  return <><div className="mx-auto max-w-screen-2xl px-4 pt-6 sm:px-6 lg:px-8"><Label htmlFor="configuration-environment">Runtime environment</Label><select id="configuration-environment" value={environment} onChange={(event) => setEnvironment(event.target.value as RuntimeEnvironment)} className="mt-1 h-10 w-full max-w-xs rounded-md border border-input bg-background px-3 text-sm">{(['development','staging','production'] as const).map((value) => <option key={value} value={value}>{value}</option>)}</select></div><ResourceList<ConfigurationVersion> title="Multi-company settings" description="Versioned, environment-specific policy with validation, impact preview, audit history, rollback, and signed portability." queryKey={`multi-company-configurations-${environment}`} load={(filters) => multiCompanyService.listConfigurationVersions({ ...filters, environment })} createPath={`${PATHS.settings}/new`} createLabel="New configuration" emptyTitle="Create operational policy" emptyDescription="Start from safe defaults and preview the effect before activation." columns={[
    { label: 'Version', render: (config) => <Link className="font-medium text-primary hover:underline" to={`${PATHS.settings}/${config.id}`}>v{config.version}</Link> }, { label: 'Environment', render: (config) => <StatusPill value={config.environment} /> }, { label: 'Schema', render: (config) => config.schema_version }, { label: 'Status', render: (config) => <StatusPill value={config.status} /> }, { label: 'Author', render: (config) => config.created_by }, { label: 'Created', render: (config) => new Date(config.created_at).toLocaleString() },
  ]} /><div className="mx-auto -mt-4 mb-8 max-w-screen-2xl px-4 sm:px-6 lg:px-8"><Card><CardHeader><CardTitle>Import signed configuration</CardTitle></CardHeader><CardContent><Label htmlFor="configuration-import">Signed JSON document</Label><input id="configuration-import" type="file" accept="application/json" className="mt-2 block w-full text-sm" onChange={(event) => { const file = event.target.files?.[0]; if (!file) return; file.text().then((value) => importMutation.mutate(value)).catch(() => setImportError('The selected file could not be read.')); }} />{importError && <p role="alert" className="mt-2 text-sm text-destructive">{importError}</p>}<p className="mt-2 text-xs text-muted-foreground">Imports never activate automatically; server signature and schema validation create a reviewable draft.</p></CardContent></Card></div></>;
}

// Configuration detail coordinates preview, signed export, activation, and rollback states.
// eslint-disable-next-line complexity
export function ConfigurationVersionDetailPage() {
  const { id } = useParams(); const client = useQueryClient(); const [impact, setImpact] = useState<Awaited<ReturnType<typeof multiCompanyService.previewConfiguration>>['data'] | null>(null); const [dialog, setDialog] = useState<'activate' | 'rollback' | null>(null);
  const query = useQuery({ queryKey: ['multi-company-configuration', id], queryFn: () => multiCompanyService.getConfigurationVersion(id!), enabled: Boolean(id) });
  const preview = useMutation({ mutationFn: () => multiCompanyService.previewConfiguration(id!), onSuccess: (result) => setImpact(result.data), onError: () => toast.error('Impact preview could not be calculated.') });
  const command = useMutation({ mutationFn: (name: 'activate' | 'rollback') => name === 'activate' ? multiCompanyService.activateConfiguration(id!, newKey()) : multiCompanyService.rollbackConfiguration(id!, { transition_key: newKey(), change_summary: 'Rollback created from configuration history workspace' }), onSuccess: () => { toast.success('Configuration command applied with audit evidence'); void client.invalidateQueries({ queryKey: ['multi-company-configuration', id] }); }, onError: () => toast.error('The configuration command was not applied.') });
  if (!id) return MissingId(); if (query.isLoading) return <LoadingPage />; if (query.error || !query.data) return <PageScaffold title="Configuration" description="Configuration version"><GovernedError error={query.error} onRetry={() => void query.refetch()} /></PageScaffold>; const config = query.data.data;
  const exportConfig = async () => { try { const result = await multiCompanyService.exportConfiguration(config.environment, config.version); const blob = new Blob([JSON.stringify(result.data, null, 2)], { type: 'application/json' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = `multi-company-${config.environment}-v${config.version}.json`; link.click(); URL.revokeObjectURL(link.href); } catch { toast.error('Signed export could not be generated.'); } };
  return <PageScaffold title={`${config.environment} configuration · v${config.version}`} description="Review the exact settings, impact, audit evidence, and reversible lifecycle before activation." actions={<><Button variant="outline" onClick={() => void exportConfig()}>Export signed JSON</Button>{config.allowed_commands.includes('update') && <Button variant="outline" onClick={() => location.assign(`${PATHS.settings}/${id}/edit`)}>Edit draft</Button>}{config.allowed_commands.includes('activate') && <Button onClick={() => setDialog('activate')}>Activate</Button>}{config.allowed_commands.includes('rollback') && <Button variant="danger" onClick={() => setDialog('rollback')}>Rollback to this version</Button>}</>}><BackButton to={PATHS.settings} /><div className="grid gap-6 lg:grid-cols-3"><Card className="lg:col-span-2"><CardHeader><CardTitle>Runtime controls</CardTitle></CardHeader><CardContent><DetailGrid entries={[[ 'Status', <StatusPill value={config.status} />], ['Draft expiry', `${config.settings.draft_expiry_hours} hours`], ['Minimum consolidation companies', config.settings.minimum_consolidation_company_count], ['Approval sides', config.settings.approval_sides.join(', ')], ['Job retry limit', config.settings.job_max_retries], ['Job timeout', `${config.settings.job_timeout_seconds} seconds`], ['Notifications', Object.values(config.settings.notification_policy).some(Boolean) ? 'Enabled' : 'Disabled'], ['Overlap policy', config.settings.allow_consolidation_overlap ? 'Allowed' : 'Rejected'], ['Pricing methods', config.settings.permitted_pricing_methods.join(', ')], ['Translation methods', config.settings.permitted_translation_methods.join(', ')], ['Extensions', config.settings.extension_enablement_keys.join(', ') || 'None'], ['Support evidence', config.correlation_id]]} /></CardContent></Card><Card><CardHeader><CardTitle>Audit</CardTitle></CardHeader><CardContent className="space-y-2 text-sm"><p><strong>Author:</strong> {config.created_by}</p><p><strong>Created:</strong> {new Date(config.created_at).toLocaleString()}</p><p><strong>Activated by:</strong> {config.activated_by || 'Not active'}</p><p><strong>Summary:</strong> {config.change_summary}</p><Button className="mt-3 w-full" variant="outline" disabled={preview.isPending} onClick={() => preview.mutate()}>{preview.isPending ? 'Simulating…' : 'Preview impact'}</Button></CardContent></Card></div>{impact && <Card><CardHeader><CardTitle>Impact preview</CardTitle></CardHeader><CardContent><div className="grid gap-4 sm:grid-cols-3"><div><p className="text-2xl font-semibold">{impact.affected_companies}</p><p className="text-sm text-muted-foreground">companies</p></div><div><p className="text-2xl font-semibold">{impact.affected_draft_transactions}</p><p className="text-sm text-muted-foreground">draft transactions</p></div><div><p className="text-2xl font-semibold">{impact.changed_keys.length}</p><p className="text-sm text-muted-foreground">changed settings</p></div></div>{impact.warnings.map((warning) => <InlineWarning key={warning}>{warning}</InlineWarning>)}</CardContent></Card>}<ConfirmDialog open={dialog !== null} onOpenChange={(open) => { if (!open) setDialog(null); }} title={dialog === 'activate' ? 'Activate configuration?' : 'Create rollback version?'} description="The server enforces separation of duties, validates safe limits, and records the prior and next values with a correlation ID. Rollback creates a new version; history is immutable." confirmLabel={command.isPending ? 'Applying…' : 'Confirm configuration change'} variant={dialog === 'rollback' ? 'danger' : 'default'} onConfirm={() => { if (dialog) command.mutate(dialog); }} /></PageScaffold>;
}

interface ConfigurationFormState { environment: RuntimeEnvironment; schema_version: string; change_summary: string; draft_expiry_hours: string; minimum_consolidation_companies: string; tolerance_min: string; tolerance_max: string; max_usd: string; allow_overlap: boolean; notifications_enabled: boolean; job_retry_limit: string; job_timeout_seconds: string; pricing_methods: readonly PricingMethod[] }
const emptyConfiguration: ConfigurationFormState = { environment: 'development', schema_version: '1.0', change_summary: '', draft_expiry_hours: String(defaultSettings.draft_expiry_hours), minimum_consolidation_companies: String(defaultSettings.minimum_consolidation_company_count), tolerance_min: defaultSettings.transfer_pricing_tolerance_min, tolerance_max: defaultSettings.transfer_pricing_tolerance_max, max_usd: defaultSettings.maximum_transaction_amount_by_currency.USD ?? '', allow_overlap: defaultSettings.allow_consolidation_overlap, notifications_enabled: Object.values(defaultSettings.notification_policy).some(Boolean), job_retry_limit: String(defaultSettings.job_max_retries), job_timeout_seconds: String(defaultSettings.job_timeout_seconds), pricing_methods: defaultSettings.permitted_pricing_methods };
function ConfigurationFormPage({ edit }: { edit: boolean }) {
  const { id } = useParams(); const navigate = useNavigate(); const [form, setForm] = useState(emptyConfiguration); const [hydrated, setHydrated] = useState(false); const current = useQuery({ queryKey: ['multi-company-configuration', id], queryFn: () => multiCompanyService.getConfigurationVersion(id!), enabled: edit && Boolean(id) });
  if (edit && current.data && !hydrated) { const c = current.data.data; setForm({ environment: c.environment, schema_version: c.schema_version, change_summary: c.change_summary, draft_expiry_hours: String(c.settings.draft_expiry_hours), minimum_consolidation_companies: String(c.settings.minimum_consolidation_company_count), tolerance_min: c.settings.transfer_pricing_tolerance_min, tolerance_max: c.settings.transfer_pricing_tolerance_max, max_usd: c.settings.maximum_transaction_amount_by_currency.USD ?? '', allow_overlap: c.settings.allow_consolidation_overlap, notifications_enabled: Object.values(c.settings.notification_policy).some(Boolean), job_retry_limit: String(c.settings.job_max_retries), job_timeout_seconds: String(c.settings.job_timeout_seconds), pricing_methods: c.settings.permitted_pricing_methods }); setHydrated(true); }
  useUnsavedChanges(true); const settings = useMemo<MultiCompanySettings>(() => ({ ...defaultSettings, draft_expiry_hours: Number(form.draft_expiry_hours), minimum_consolidation_company_count: Number(form.minimum_consolidation_companies), transfer_pricing_tolerance_min: form.tolerance_min, transfer_pricing_tolerance_max: form.tolerance_max, maximum_transaction_amount_by_currency: { USD: form.max_usd }, allow_consolidation_overlap: form.allow_overlap, notification_policy: { approval: form.notifications_enabled, dispute: form.notifications_enabled, failure: form.notifications_enabled, completion: form.notifications_enabled }, job_max_retries: Number(form.job_retry_limit), job_timeout_seconds: Number(form.job_timeout_seconds), permitted_pricing_methods: form.pricing_methods }), [form]);
  const mutation = useMutation({ mutationFn: () => edit && id && current.data ? multiCompanyService.updateConfigurationVersion(id, { expected_version: current.data.data.version, settings, change_summary: form.change_summary }) : multiCompanyService.createConfigurationVersion({ environment: form.environment, schema_version: form.schema_version, settings, change_summary: form.change_summary }), onSuccess: (result) => { toast.success('Configuration draft saved'); navigate(`${PATHS.settings}/${result.data.id}`); }, onError: () => toast.error('Server validation rejected the configuration draft.') }); if (edit && current.isLoading) return <LoadingPage />;
  const number = (key: 'draft_expiry_hours'|'minimum_consolidation_companies'|'tolerance_min'|'tolerance_max'|'max_usd'|'job_retry_limit'|'job_timeout_seconds', label: string, help: string) => <div><Label htmlFor={`config-${key}`}>{label}</Label><Input id={`config-${key}`} type="number" value={form[key]} onChange={(event) => setForm({ ...form, [key]: event.target.value })} /><p className="mt-1 text-xs text-muted-foreground">{help}</p></div>;
  return <PageScaffold title={edit ? 'Edit configuration draft' : 'Create configuration version'} description="Every operational threshold is runtime-configurable, versioned, validated, auditable, and reversible."><BackButton to={PATHS.settings} /><form onSubmit={(event) => { event.preventDefault(); if (!form.change_summary.trim() || Number(form.draft_expiry_hours) < 1 || Number(form.minimum_consolidation_companies) < 2 || Number(form.job_retry_limit) < 0 || Number(form.job_retry_limit) > 10 || Number(form.job_timeout_seconds) < 10 || Number(form.job_timeout_seconds) > 3600 || Number(form.tolerance_min) > Number(form.tolerance_max)) { toast.error('Review safe bounds, tolerance order, and change summary.'); return; } mutation.mutate(); }}><Card><CardContent className="grid gap-5 p-6 md:grid-cols-2"><div><Label htmlFor="config-environment">Environment</Label><select id="config-environment" disabled={edit} value={form.environment} onChange={(event) => setForm({ ...form, environment: event.target.value as RuntimeEnvironment })} className="h-10 w-full rounded-md border border-input bg-background px-3 text-sm">{(['development','staging','production'] as const).map((env) => <option key={env}>{env}</option>)}</select></div><div><Label htmlFor="config-schema">Schema version</Label><Input id="config-schema" value={form.schema_version} onChange={(event) => setForm({ ...form, schema_version: event.target.value })} /></div>{number('draft_expiry_hours','Draft expiry (hours)','Safe bound: 1–8760 hours.')}{number('minimum_consolidation_companies','Minimum consolidation companies','Safe lower bound: 2.')}{number('tolerance_min','Pricing tolerance minimum','Must not exceed the maximum.')}{number('tolerance_max','Pricing tolerance maximum','Server-enforced method tolerance.')}{number('max_usd','Maximum USD transaction','Transactions beyond this limit are unsavable.')}{number('job_retry_limit','Job retry limit','Safe bound: 0–10 attempts.')}{number('job_timeout_seconds','Job timeout (seconds)','Safe bound: 10–3600 seconds.')}<div className="space-y-3"><label className="flex items-center gap-2 text-sm"><input type="checkbox" checked={form.allow_overlap} onChange={(event) => setForm({ ...form, allow_overlap: event.target.checked })} />Allow consolidation period overlap</label><label className="flex items-center gap-2 text-sm"><input type="checkbox" checked={form.notifications_enabled} onChange={(event) => setForm({ ...form, notifications_enabled: event.target.checked })} />Enable operational notifications</label></div><div className="md:col-span-2"><Label htmlFor="config-summary">Change summary</Label><Textarea id="config-summary" value={form.change_summary} onChange={(event) => setForm({ ...form, change_summary: event.target.value })} placeholder="Explain why this policy version is needed and its expected effect." /></div><div className="md:col-span-2"><InlineWarning>Saving creates an inactive draft. Validate and preview the impact from its detail page; a different authorized subject must activate production policy.</InlineWarning></div><Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? 'Saving…' : 'Save configuration draft'}</Button></CardContent></Card></form></PageScaffold>;
}
